function TonDepositScreen({ onSelectMethod }) {
  const methods = [
    {
      id: 'crypto-wallet',
      title: 'Перевод из Крипто Кошелька',
      subtitle: 'Внесите из вашего Крипто Кошелька',
      icon: <span className="ton-deposit-icon-wrap ton-deposit-icon-crypto">{ICON_CRYPTO_WALLET}</span>,
    },
    {
      id: 'stablecoins',
      title: 'Стейблкоины',
      subtitle: 'Зачислятся 1:1 как USDT в сети TON',
      icon: (
        <span className="ton-deposit-icon-stablecoins">
          <span className="ton-deposit-stablecoin-first">{ICON_USDC}</span>
          <span className="ton-deposit-stablecoin-second">{ICON_USDT}</span>
        </span>
      ),
    },
    {
      id: 'other-crypto',
      title: 'Другие криптовалюты',
      subtitle: 'Будут конвертированы в Toncoin',
      icon: ICON_OTHER_CRYPTO,
    },
    {
      id: 'external-wallet',
      title: 'Внешний кошелёк',
      subtitle: 'Получить с другого TON Кошелька',
      icon: <span className="ton-deposit-icon-wrap ton-deposit-icon-external">{ICON_EXTERNAL_WALLET}</span>,
    },
  ];

  const handleSelect = (id) => {
    if (typeof onSelectMethod === 'function') {
      onSelectMethod(id);
    }
  };

  return (
    <div className="ton-deposit-screen">
      <h1 className="ton-deposit-title">Как пополнить?</h1>
      <div className="ton-deposit-list">
        {methods.map((item) => (
          <button
            key={item.id}
            type="button"
            className="ton-deposit-item"
            onClick={() => handleSelect(item.id)}
          >
            <div className="ton-deposit-item-icon">{item.icon}</div>
            <div className="ton-deposit-item-content">
              <span className="ton-deposit-item-title">{item.title}</span>
              <span className="ton-deposit-item-subtitle">{item.subtitle}</span>
            </div>
            <span className="ton-deposit-item-chevron">{CHEVRON_RIGHT}</span>
          </button>
        ))}
      </div>
    </div>
  );
}

export default TonDepositScreen;
